import{_ as t,o,c as a,ag as n}from"./chunks/framework.DZKik_R9.js";const m=JSON.parse('{"title":"Module Federation et intégration hôte","description":"","frontmatter":{},"headers":[],"relativePath":"solution/module-federation.md","filePath":"solution/module-federation.md"}'),r={name:"solution/module-federation.md"};function d(s,e,c,i,l,u){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="module-federation-et-integration-hote" tabindex="-1">Module Federation et intégration hôte <a class="header-anchor" href="#module-federation-et-integration-hote" aria-label="Permalink to &quot;Module Federation et intégration hôte&quot;">​</a></h1><h2 id="objectif" tabindex="-1">Objectif <a class="header-anchor" href="#objectif" aria-label="Permalink to &quot;Objectif&quot;">​</a></h2><p>Permettre à un <strong>site hôte</strong> (React, autre stack, bundler Vite/Webpack) de :</p><ol><li>Charger le <strong>remote</strong> déployé depuis <code>abtest-solution</code> (<code>apps/remote</code>).</li><li>Appeler <strong><code>/api/evaluate</code></strong> avec un contexte (cookies, URL, etc.).</li><li>Afficher la <strong>variante</strong> (JS/CSS/composants) retournée par le moteur.</li></ol><p>Ce flux correspond aux campagnes <strong><code>type: frontend</code></strong> (livraison par assets). Pour les campagnes <strong><code>type: backend</code></strong>, la variante s’applique <strong>côté serveur</strong> : le hôte appelle <strong><code>POST /api/evaluate</code></strong> depuis <strong>sa stack serveur</strong> (ou BFF), consomme notamment <strong><code>variation.featureFlags</code></strong>, et ne passe <strong>pas</strong> par le slot Module Federation pour la décision (voir <a href="./campaigns-segments/campaigns#intégration-backend-feature-flags">Campagnes — intégration backend</a>).</p><h2 id="etapes" tabindex="-1">Étapes <a class="header-anchor" href="#etapes" aria-label="Permalink to &quot;Étapes&quot;">​</a></h2><ol><li><strong>Build</strong> du workspace <code>apps/remote</code> et hébergement statique (CDN, bucket, etc.).</li><li><strong>Déclarer</strong> le remote dans la config Module Federation du hôte (URL du <code>remoteEntry</code> selon build).</li><li><strong>Importer</strong> au runtime les modules exposés (composant, hooks, etc., selon l’API du remote).</li></ol><p>Le dépôt <strong><code>small-webserver</code></strong> illustre une chaîne complète en labo.</p><h2 id="parametres-d-url-remote-abtestslot" tabindex="-1">Paramètres d’URL (remote <code>AbTestSlot</code>) <a class="header-anchor" href="#parametres-d-url-remote-abtestslot" aria-label="Permalink to &quot;Paramètres d’URL (remote `AbTestSlot`)&quot;">​</a></h2><p>Le composant exposé lit notamment :</p><table tabindex="0"><thead><tr><th>Paramètre</th><th>Description</th></tr></thead><tbody><tr><td>(assets communs)</td><td>Si le <code>config.json</code> de la campagne définit <strong><code>sharedJsPath</code></strong> / <strong><code>sharedCssPath</code></strong>, le remote les injecte <strong>avant</strong> les <code>jsPath</code> / <code>cssPath</code> de la variante choisie.</td></tr><tr><td><code>ab_campaign_id</code></td><td><strong>Nombre</strong> (id campagne 10000–99999).</td></tr><tr><td><code>ab_simulation=1</code></td><td>Mode simulation côté API (<code>simulation</code> non nul) : campagne inactive, hors segment ou sans consentement « mesure » peuvent quand même servir une variante.</td></tr><tr><td><code>ab_force=1</code></td><td>Alias de <code>ab_simulation=1</code> (même effet).</td></tr><tr><td><code>ab_variation_id</code></td><td>Optionnel : <strong>nombre</strong> (id de variation) pour forcer une variante (souvent avec simulation).</td></tr><tr><td><code>ab_skip=1</code></td><td>N’appelle pas <code>/api/evaluate</code> et n’injecte aucun asset : le test ne se charge pas pour cette page.</td></tr></tbody></table><h2 id="props-du-composant-abtestslot" tabindex="-1">Props du composant <code>AbTestSlot</code> <a class="header-anchor" href="#props-du-composant-abtestslot" aria-label="Permalink to &quot;Props du composant `AbTestSlot`&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Prop</th><th>Rôle</th></tr></thead><tbody><tr><td><code>navigationDependency</code></td><td>Optionnel : chaîne qui change quand la vue SPA change sans URL (ex. <code>location.key</code> React Router).</td></tr></tbody></table><p>Variable d’environnement côté build : <code>VITE_ABTEST_API_URL</code> (sinon <code>http://localhost:5002</code> par défaut en dev).</p><h2 id="contexte-navigateur" tabindex="-1">Contexte navigateur <a class="header-anchor" href="#contexte-navigateur" aria-label="Permalink to &quot;Contexte navigateur&quot;">​</a></h2><p>Le remote alimente notamment :</p><table tabindex="0"><thead><tr><th>Champ dans <code>context</code></th><th>Rôle</th></tr></thead><tbody><tr><td><code>cookies</code></td><td>Objet clé → valeur ; consentement (<code>consent-config</code>) et règles segment <code>cookie</code>.</td></tr><tr><td><code>visitorType</code></td><td><code>new</code> | <code>returning</code> (souvent via cookie démo <code>abtest_returning</code>).</td></tr><tr><td><code>userId</code></td><td>Identifiant stable par navigateur (remote : <code>localStorage</code> + cookie miroir <code>abtest_vid</code>), utilisé pour le bucketing.</td></tr></tbody></table><p><strong>Géo</strong> (<code>country</code>, <code>region</code>, <code>city</code>) : en général injectée par <strong>BFF</strong>, <strong>edge</strong> ou <strong>CDN</strong>, pas uniquement par le navigateur — voir <a href="./campaigns-segments/segments#contexte-usercontext">Règles et contexte</a>.</p><p>Voir <a href="./campaigns-segments/segments">Segments</a>, <a href="./consent">Consentement</a> et <a href="./visitor-assignments">Visiteur et assignations</a> (sticky, SPA, module fédéré <code>./visitorId</code>).</p>',19)])])}const g=t(r,[["render",d]]);export{m as __pageData,g as default};
